use std::collections::HashMap;

fn solve(points: Vec<Vec<i64>>) -> i64 {
    const MOD: i64 = 1_000_000_007;
    let inv_2: i64 = 500_000_004; // Modular inverse of 2 modulo 1e9+7

    let mut freq = HashMap::new();
    for point in points {
        let y = point[1];
        *freq.entry(y).or_insert(0) += 1;
    }

    let mut total = 0;
    let mut sum_squares = 0;

    for &count in freq.values() {
        let c = count * (count - 1) / 2;
        total = (total + c) % MOD;
        sum_squares = (sum_squares + c * c) % MOD;
    }

    let total_sq = (total * total) % MOD;
    let diff = (total_sq - sum_squares) % MOD;
    let diff = (diff + MOD) % MOD;
    let ans = (diff * inv_2) % MOD;

    ans
}
